function Badge(props){var c={default:"#f59e0b",success:"#10b981",info:"#38bdf8",error:"#ef4444",warning:"#f59e0b",muted:"#94a3b8"};var col=c[props.variant||"default"];return <span style={{color:col,background:col+"18",padding:"4px 12px",borderRadius:20,fontSize:10,fontWeight:700,letterSpacing:0.5,textTransform:"uppercase"}}>{props.children}</span>}
async function fetchCands(pg,ps,f){pg=pg||1;ps=ps||20;f=f||{};var u=MAN+"/candidates/?page="+pg+"&page_size="+ps;if(f.source_type&&f.source_type!=="all")u+="&source_type="+f.source_type;if(f.search)u+="&full_name="+encodeURIComponent(f.search)+"&case_insensitive=true";if(f.position)u+="&current_position="+encodeURIComponent(f.position);if(f.desc)u+="&description="+encodeURIComponent(f.desc);if(f.location)u+="&candidate_location="+encodeURIComponent(f.location);var r=await fetch(u,{headers:{"Authorization":"Token "+MT}});if(!r.ok)throw new Error("Manatal "+r.status);var d=await r.json();return{candidates:d.results||[],total:d.count||0,hasNext:!!d.next,hasPrev:!!d.previous}}
async function fetchJobs(pg,ps){pg=pg||1;ps=ps||20;var r=await fetch(MAN+"/jobs/?page="+pg+"&page_size="+ps+"&status=active",{headers:{"Authorization":"Token "+MT}});if(!r.ok)throw new Error("Jobs "+r.status);var d=await r.json();return{jobs:d.results||[],total:d.count||0,hasNext:!!d.next,hasPrev:!!d.previous}}
async function fetchOrgs(){var r=await fetch(MAN+"/organizations/?page_size=50",{headers:{"Authorization":"Token "+MT}});if(!r.ok)return[];var d=await r.json();return d.results||[]}
async function fetchJobMatches(jobId){var r=await fetch(MAN+"/matches/?job_id="+jobId+"&page_size=100",{headers:{"Authorization":"Token "+MT}});if(!r.ok)return[];var d=await r.json();return d.results||[]}
async function logNote(id,txt){await fetch(MAN+"/candidates/"+id+"/notes/",{method:"POST",headers:{"Authorization":"Token "+MT,"Content-Type":"application/json"},body:JSON.stringify({info:txt})})}
async function fetchJobNotes(jobId){try{var r=await fetch(MAN+"/jobs/"+jobId+"/notes/",{headers:{"Authorization":"Token "+MT}});if(!r.ok)return"";var d=await r.json();var notes=(d.result||d.results||[]);return notes.map(function(n){return strip(n.info||"")}).join("\n")}catch(e){return""}}
function wait(ms){return new Promise(function(r){setTimeout(r,ms)})}
async function downloadRFResume(c){
var data=c._rfData;if(!data)return;
try{var r=await fetch("/api/resume-pdf",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(data)});
if(!r.ok)throw new Error("PDF generation failed");
var blob=await r.blob();var url=URL.createObjectURL(blob);var a=document.createElement("a");a.href=url;a.download=c.full_name+" - Resume.pdf";a.click();URL.revokeObjectURL(url)}catch(e){console.error("Resume PDF error:",e);alert("Could not generate resume PDF: "+e.message)}}
async function apiFetch(body,retries){retries=retries||5;for(var attempt=0;attempt<retries;attempt++){var r=await fetch(API,{method:"POST",headers:AH,body:JSON.stringify(body)});if(r.status===429||r.status===529||r.status===500||r.status===503){var delay=Math.pow(2,attempt)*5000;console.log("API "+r.status+", waiting "+delay/1000+"s (attempt "+(attempt+1)+"/"+retries+")...");await wait(delay);continue}return r.json()}throw new Error("API unavailable after "+retries+" retries")}async function safeFetch(pg,ps,f){try{var r=await fetchCands(pg,ps,f);return r}catch(e){return{candidates:[],total:0,hasNext:false,hasPrev:false}}}
function getMatchCache(jobId){try{var c=JSON.parse(window.localStorage.getItem("matchCache_"+jobId));if(c&&c.ts&&Date.now()-c.ts<14400000)return c.matches;return null}catch(e){return null}}
function setMatchCache(jobId,matches){try{window.localStorage.setItem("matchCache_"+jobId,JSON.stringify({ts:Date.now(),matches:matches.map(function(m){return{id:m.id,full_name:m.full_name,email:m.email,phone_number:m.phone_number,current_position:m.current_position,current_company:m.current_company,candidate_location:m.candidate_location,latest_degree:m.latest_degree,latest_university:m.latest_university,source_type:m.source_type,description:m.description,resume:m.resume,_applied:m._applied,_scores:m._scores,_rfData:m._rfData||null,_linkedin:m._linkedin||"",_noResume:m._noResume||false,_skills:m._skills||"",_enrichedVia:m._enrichedVia||""}})}))}catch(e){}}
async function matchCandidates(job,onStatus){
var cached=getMatchCache(job.id);
if(cached&&cached.length>0){onStatus("Loaded cached results. Run match again to refresh.");return cached}
onStatus("Step 1/10: Loading screening criteria and applicants...");
var jobDescFull=strip(job.description||"");
var jobDescShort=jobDescFull.substring(0,1200);
var jobNotes="";try{jobNotes=await fetchJobNotes(job.id)}catch(e){}
var all=[];var seen={};
await wait(300);
try{var appMatches=await fetchJobMatches(job.id);var appCands=appMatches.slice(0,15);for(var ai=0;ai<appCands.length;ai++){var am=appCands[ai];await wait(400);try{var acr=await fetch(MAN+"/candidates/?id="+am.candidate,{headers:{"Authorization":"Token "+MT}});if(acr.ok){var acd=await acr.json();var ac=(acd.results&&acd.results[0])||null;if(ac&&!seen[ac.id]){seen[ac.id]=true;ac._applied=true;all.push(ac)}}}catch(e){}}}catch(e){}
onStatus("Step 2/10: Found "+all.length+" applicants. Generating search strategy...");
await wait(400);
var kwData=await apiFetch({model:"claude-haiku-4-5-20251001",max_tokens:300,messages:[{role:"user",content:"You are helping search a recruiting database. Extract search terms from this job posting.\n\nReturn a JSON object with:\n- keywords: array of 8 SINGLE-WORD skills, tools, or domain terms ACTUALLY relevant to THIS job, matched to its field (finance e.g. 'Excel','LBO','Valuation','Modeling'; engineering e.g. 'Python','Kafka','React')\n- titles: array of 3 SINGLE-WORD job-title terms for THIS role (finance e.g. 'Analyst','Associate','Banking'; engineering e.g. 'Backend','Engineer','Developer')\n- companies: array of 3 company names where ideal candidates might work (e.g. 'Google', 'Stripe')\n\nReturn ONLY the JSON object.\n\nJob: "+job.position_name+"\nDescription: "+jobDescShort}]});
var kws=[],titles=[],companies=[];
try{var parsed=JSON.parse((kwData.content||[]).map(function(b){return b.text||""}).join("").replace(/```json|```/g,"").trim());kws=parsed.keywords||[];titles=parsed.titles||[];companies=parsed.companies||[]}catch(e){kws=job.position_name.split(" ").filter(function(w){return w.length>3})}
var allSearchTerms=kws.concat(titles).filter(function(v,i,a){return a.indexOf(v)===i});
onStatus("Step 3/10: Searching "+allSearchTerms.length+" keywords + "+companies.length+" companies...");
for(var ki=0;ki<allSearchTerms.length;ki++){var kw=allSearchTerms[ki];
onStatus("Step 3/10: Searching '"+kw+"' ("+(ki+1)+"/"+allSearchTerms.length+")...");
await wait(500);
var r1=await safeFetch(1,40,{position:kw});
for(var ci=0;ci<r1.candidates.length;ci++){var c=r1.candidates[ci];if(!seen[c.id]){seen[c.id]=true;all.push(c)}}
if(ki<8){await wait(500);var r2=await safeFetch(1,40,{desc:kw});for(var ci2=0;ci2<r2.candidates.length;ci2++){var c2=r2.candidates[ci2];if(!seen[c2.id]){seen[c2.id]=true;all.push(c2)}}}
if(r1.hasNext&&ki<6){await wait(500);var r3=await safeFetch(2,40,{position:kw});for(var ci3=0;ci3<r3.candidates.length;ci3++){var c3=r3.candidates[ci3];if(!seen[c3.id]){seen[c3.id]=true;all.push(c3)}}}
if(all.length>300)break}
for(var coi=0;coi<companies.length&&all.length<320;coi++){await wait(500);onStatus("Step 3/10: Searching company '"+companies[coi]+"'...");var cr=await safeFetch(1,15,{desc:companies[coi]});for(var cci=0;cci<cr.candidates.length;cci++){var cc=cr.candidates[cci];if(!seen[cc.id]){seen[cc.id]=true;all.push(cc)}}}
var jobLoc=(job.address||"").split(",")[0].trim();
if(jobLoc&&jobLoc.length>2){await wait(500);var lr=await safeFetch(1,40,{location:jobLoc});for(var li=0;li<lr.candidates.length;li++){var lc=lr.candidates[li];if(!seen[lc.id]){seen[lc.id]=true;all.push(lc)}}}
// === ZOOMINFO AUTO-ENRICHMENT ===
try{
var toEnrich=all.filter(function(c){return !c.email&&c.full_name&&(c.current_company||c.current_position)});
if(toEnrich.length>0){
onStatus("Step 6/10: Enriching "+toEnrich.length+" candidates missing emails via ZoomInfo...");
var enrichRes=await fetch("/api/enrich-candidates",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({candidates:toEnrich.map(function(c){return{id:c.id,firstName:(c.full_name||"").split(" ")[0]||"",lastName:(c.full_name||"").split(" ").slice(1).join(" ")||"",company:c.current_company||"",email:c.email||null}})})});
if(enrichRes.ok){var enrichData=await enrichRes.json();var enrichMap={};(enrichData.candidates||[]).forEach(function(ec){if(ec.email&&ec.id)enrichMap[String(ec.id)]=ec});
all.forEach(function(c){var e=enrichMap[String(c.id)];if(e){c.email=e.email;c.phone_number=c.phone_number||e.phone||"";c._enrichedVia="zoominfo"}});
onStatus("Step 6/10: ZoomInfo enriched "+enrichData.enrichedCount+" emails ("+enrichData.fromCache+" cached, "+enrichData.fromZi+" new lookups)");}
}}catch(e){console.log("ZoomInfo enrich error:",e)}
// === END ZOOMINFO ===
// === STAGE 1: HAIKU QUICK FILTER ===
onStatus("Step 7/10: Stage 1 — Haiku filtering "+all.length+" candidates to top 25...");
(function(){var _seen={},_d=[];all.forEach(function(c){var _k=((c.email||"")+"").toLowerCase().trim();if(!_k){_k="n:"+((c.full_name||"")+"").toLowerCase().trim()}if(_k==="n:"){_d.push(c);return}if(!_seen[_k]){_seen[_k]=1;_d.push(c)}});all=_d})();all.forEach(function(c){if(!c._skills&&Array.isArray(c.skills)&&c.skills.length){c._skills=c.skills.map(function(s){return s&&s.skill_name?s.skill_name:(typeof s==="string"?s:"")}).filter(Boolean).join(", ")}});var shortProfiles=all.map(function(c){return JSON.stringify({id:c.id,name:c.full_name,position:c.current_position,company:c.current_company,location:c.candidate_location,source:c.source_type,applied:c._applied?"YES":"no",skills:c._skills||"",resume_snippet:(c.description||"").substring(0,400)})});
var filterPrompt="You are a recruiting assistant. Quickly filter these candidates for this job. Select the TOP 25 most promising candidates based on title, company, skills, and resume snippet.\n\nJOB: "+job.position_name+"\nLOCATION: "+(job.address||"Not specified")+"\nDESCRIPTION: "+jobDescShort+"\n\nCANDIDATES ("+all.length+" total):\n"+shortProfiles.join("\n")+"\n\nReturn ONLY a JSON array of the 25 best candidate IDs: [123, 456, \"rf_789\", ...]";
var filterData=await apiFetch({model:"claude-haiku-4-5-20251001",max_tokens:500,messages:[{role:"user",content:filterPrompt}]});
var filterTxt=(filterData.content||[]).map(function(b){return b.text||""}).join("");
var top15ids=[];
try{var idMatch=filterTxt.match(/\[[\s\S]*?\]/);if(idMatch){top15ids=JSON.parse(idMatch[0]).map(function(id){return String(id)})}}catch(e){console.log("Filter parse error:",e)}
var shortlisted=[];
if(top15ids.length>0){shortlisted=all.filter(function(c){return top15ids.indexOf(String(c.id))!==-1});if(shortlisted.length<5){var remaining=all.filter(function(c){return top15ids.indexOf(String(c.id))===-1});shortlisted=shortlisted.concat(remaining.slice(0,25-shortlisted.length))}}
if(shortlisted.length<5){shortlisted=all.filter(function(c){return c._applied}).concat(all.filter(function(c){return!c._applied})).slice(0,25)}
onStatus("Step 8/10: Stage 1 complete — "+shortlisted.length+" shortlisted. Building deep profiles...");
// === STAGE 2: SONNET DEEP ANALYSIS ===
var fullSOW=jobDescFull.substring(0,6000);
var notesCtx=jobNotes?"\n\nSCREENING CRITERIA AND CLIENT FEEDBACK (CRITICAL - follow these strictly):\n"+jobNotes.substring(0,2000):"";
var deepProfiles=shortlisted.map(function(c){
var fullResume=(c.description||"").substring(0,4000);
var profile={id:c.id,name:c.full_name,email:c.email,position:c.current_position,company:c.current_company,location:c.candidate_location,degree:c.latest_degree,university:c.latest_university,source:c.source_type,applied:c._applied?"YES":"no"};
if(fullResume.length>50)profile.full_resume=fullResume;
if(c._skills)profile.skills=c._skills;
if(c._rfData&&c._rfData.candidate_summary)profile.summary=c._rfData.candidate_summary.substring(0,800);
return JSON.stringify(profile)});
onStatus("Step 9/10: Stage 2 — Sonnet deep analysis of "+shortlisted.length+" candidates with full resumes + full SOW...");
var rankBody={model:"claude-sonnet-4-6",max_tokens:12000,messages:[{role:"user",content:"You are an expert technical recruiter at a top staffing firm. You have been given the FULL Statement of Work and the FULL resumes for "+shortlisted.length+" pre-screened candidates. Perform a thorough analysis and select the BEST 10.\n\nHARD REQUIREMENTS: Treat any explicit must-have qualifications in the SCREENING CRITERIA / notes as mandatory. If a candidate does not clearly satisfy every must-have, cap their overall score at 40, and name the missing requirement(s) in the reasoning; do not place them in the top tier.\n\nSCORING RUBRIC (score each 0-100):\n1. SKILLS MATCH (40%): Deep evaluation — do their specific technical skills, certifications, and tools align with the SOW requirements? Look for exact matches.\n2. EXPERIENCE LEVEL (25%): Evaluate years AND depth. Look at actual project descriptions, responsibilities, and achievements in the resume.\n3. INDUSTRY FIT (15%): Have they worked in the same industry or domain? Consider company pedigree and sector relevance.\n4. LOCATION (10%): Near the job location or willing to relocate? Is the role remote?\n5. EDUCATION (10%): Does their education support the role? Look for relevant degrees, certifications, PE licenses.\n\nCRITICAL RULES:\n- Candidates marked applied=YES have already applied to THIS job. STRONGLY prioritize unless clearly unqualified.\n- Follow screening criteria and auto-reject triggers STRICTLY if provided.\n- Read the FULL RESUME carefully — this is a thorough evaluation, not a keyword scan.\n- CRITICAL: Evaluate ALL candidates equally regardless of source. RecruiterFlow and Recruitee candidates have skills lists and experience summaries that should be weighed equally to full resumes.\n- Provide SPECIFIC reasons citing actual experience, projects, certifications, and skills from their resume.\n\nFULL STATEMENT OF WORK / JOB DESCRIPTION:\n"+fullSOW+"\n\nJOB DETAILS:\nTITLE: "+job.position_name+"\nLOCATION: "+(job.address||"Not specified")+"\nSALARY: $"+(job.salary_min||"?")+" - $"+(job.salary_max||"?")+"\nREMOTE: "+(job.is_remote?"Yes":"No")+"\nCONTRACT: "+(job.contract_details||"full_time")+notesCtx+"\n\nCANDIDATES WITH FULL RESUMES ("+shortlisted.length+" shortlisted):\n"+deepProfiles.join("\n\n")+"\n\nIMPORTANT: Respond with ONLY the JSON array. Do NOT write any analysis or thinking first. Start immediately with [ and end with ].\n[{\"id\":123,\"overall\":85,\"skills\":90,\"experience\":80,\"industry\":75,\"location\":90,\"education\":85,\"reason\":\"1-2 sentence reason citing SPECIFIC experience, skills, or gaps from their resume\"}]\n\nOverall = skills*0.4 + experience*0.25 + industry*0.15 + location*0.1 + education*0.1"},{role:"assistant",content:"["}]};
var rankData=await apiFetch(rankBody);var rankTxt=(rankData.content||[]).map(function(b){return b.text||""}).join("");
onStatus("Step 10/10: Processing results...");
var _rt=("["+rankTxt).replace(/```json|```/g,"").trim();var _st=_rt.indexOf("[");var _js=_st>=0?_rt.slice(_st):_rt;var _le=_js.lastIndexOf("]");if(_le>=0){_js=_js.slice(0,_le+1)}else{var _lb=_js.lastIndexOf("}");if(_lb>=0){_js=_js.slice(0,_lb+1)+"]"}}try{var scored=JSON.parse(_js);var scoreMap={};scored.forEach(function(s){scoreMap[String(s.id)]=s});var matched=shortlisted.filter(function(c){return scoreMap[String(c.id)]}).slice(0,10);if(matched.length===0){var scoredIds=scored.map(function(s){return Number(s.id)});matched=shortlisted.filter(function(c){return scoredIds.indexOf(c.id)!==-1}).slice(0,10)}if(matched.length===0&&scored.length>0){matched=scored.map(function(s){var found=shortlisted.find(function(a){return a.id===s.id||a.id===Number(s.id)||String(a.id)===String(s.id)});if(!found)found=all.find(function(a){return String(a.id)===String(s.id)});if(found){found=Object.assign({},found);found._scores=s}return found}).filter(Boolean).slice(0,10)}else{matched.forEach(function(c){c._scores=scoreMap[String(c.id)]||{}})}setMatchCache(job.id,matched);return matched}catch(e){console.log("Score parse error:",e,rankTxt);var fallback=shortlisted.filter(function(c){return c.email}).slice(0,5);return fallback}}
