function extractRFKeywords(job){var text=(job.position_name+" "+(strip(job.description||""))).toLowerCase();var kws=new Set();job.position_name.split(/[\s\-\/]+/).filter(function(w){return w.length>2&&["the","and","for","with","senior","junior","lead","manager","director"].indexOf(w.toLowerCase())===-1}).forEach(function(w){kws.add(w.toLowerCase())});var patterns=[/civil engineer/gi,/architect/gi,/project manager/gi,/designer/gi,/structural/gi,/transportation/gi,/roadway/gi,/drainage/gi,/utilities/gi,/water.*wastewater/gi,/hvac/gi,/mechanical/gi,/electrical/gi,/mep/gi,/land development/gi,/stormwater/gi,/autocad/gi,/civil 3d/gi,/revit/gi,/microstation/gi,/pe license/gi,/professional engineer/gi,/eit/gi,/grading/gi,/permitting/gi,/fdot/gi,/construction admin/gi,/bridge/gi,/survey/gi,/bim/gi,/openroads/gi,/commissioning/gi,/power/gi,/infrastructure/gi];patterns.forEach(function(p){var m=text.match(p);if(m)m.forEach(function(match){kws.add(match.trim().toLowerCase())})});return Array.from(kws).filter(function(k){return k.length>1}).slice(0,12)}
var handleRFSelectJob=function(job){setRfJob(job);setRfKws(extractRFKeywords(job));setRfCands([]);setRfScoring({});setRfExpandedCard(null);setRfShortlisted(new Set());setRfShowShortlistOnly(false)};
var handleRFSearch=async function(){setRfLoading(true);setRfCands([]);setRfScoring({});setRfShortlisted(new Set());setRfShowShortlistOnly(false);try{var rfSkills=rfKws.map(function(k){return[k]});var actionName=rfAppliedOnly?"matchAppliedCandidates":"matchCandidates";var res=await fetch("/api/recruiterflow",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:actionName,params:{skillSets:rfSkills,maxTotal:200,checkLimit:60}})});if(res.ok){var data=await res.json();var cands=(data.candidates||[]).map(function(c){var cand={id:"rf_"+c.rf_id,name:c.full_name,title:c.current_position||"",company:c.current_company||"",location:"",email:c.email||"",phone:c.phone_number||"",source:c._jobs?"applied":"recruiterflow",skills:(c.skills||[]).join(", "),experience_summary:c.resume_text||c.candidate_summary||"",linkedin:c.linkedin||"",_rfData:{full_name:c.full_name,email:c.email,phone_number:c.phone_number,current_position:c.current_position,current_company:c.current_company,skills:c.skills||[],linkedin:c.linkedin||"",experience:c.raw_experience||[],education:c.raw_education||[],candidate_summary:c.candidate_summary||""}};if(c._jobs){cand._jobs=c._jobs}return cand});setRfCands(cands);if(rfAppliedOnly){toast({title:"Found "+cands.length+" applied candidates",detail:"Checked "+data.totalChecked+" of "+data.totalSearched+" skill matches",status:"success"})}else{toast({title:"Found "+cands.length+" candidates",status:"success"})}}else{toast({title:"RF search failed",detail:"Status: "+res.status,status:"error"})}}catch(e){toast({title:"RF search failed",detail:e.message,status:"error"})}setRfLoading(false)};
var handleRFScore=async function(candidate){if(!rfJob)return;setRfScoring(function(p){var n=Object.assign({},p);n[candidate.id]={loading:true};return n});try{var d=await apiFetch({model:"claude-haiku-4-5-20251001",max_tokens:500,messages:[{role:"user",content:'You are an AEC recruiting match scorer. Score this candidate against this job on a scale of 0-100. Return ONLY a JSON object with: {"score": <number>, "grade": "<A/B/C/D/F>", "strengths": ["<strength1>", "<strength2>"], "gaps": ["<gap1>"], "summary": "<one sentence>"}\n\nJOB:\n'+rfJob.position_name+"\n"+strip(rfJob.description||"").substring(0,1500)+"\n\nCANDIDATE:\nName: "+candidate.name+"\nTitle: "+(candidate.title||"N/A")+"\nCompany: "+(candidate.company||"N/A")+"\nSkills: "+(candidate.skills||"N/A")+"\nExperience: "+(candidate.experience_summary||"N/A").substring(0,1500)}]});var txt=(d.content||[]).map(function(b){return b.text||""}).join("");var result=JSON.parse(txt.replace(/```json|```/g,"").trim());setRfScoring(function(p){var n=Object.assign({},p);n[candidate.id]=result;return n})}catch(e){setRfScoring(function(p){var n=Object.assign({},p);n[candidate.id]={score:0,grade:"?",strengths:[],gaps:[],summary:"Scoring failed"};return n})}};
var handleRFScoreAll=async function(){setRfScoringAll(true);for(var i=0;i<rfCands.length;i++){if(!rfScoring[rfCands[i].id])await handleRFScore(rfCands[i])}setRfScoringAll(false)};
var rfAddKeyword=function(){var kw=rfCustomKw.trim().toLowerCase();if(kw&&rfKws.indexOf(kw)===-1){setRfKws(function(p){return p.concat([kw])});setRfCustomKw("")}};
