var rfGC=function(grade){var m={A:{color:"#10b981",bg:"rgba(16,185,129,0.1)"},B:{color:"#a3e635",bg:"rgba(163,230,53,0.1)"},C:{color:"#f59e0b",bg:"rgba(245,158,11,0.1)"},D:{color:"#fb923c",bg:"rgba(251,146,60,0.1)"},F:{color:"#ef4444",bg:"rgba(239,68,68,0.1)"}};return m[grade]||{color:"#78716c",bg:"rgba(120,113,108,0.1)"}};
