var doEnrich=async function(jobId){
var matched=matches[jobId];if(!matched)return;
var missing=matched.filter(function(c){return !c.email&&c.full_name});
if(missing.length===0){toast({title:"All candidates already have emails",status:"info"});return}
setEnriching(jobId);
try{var res=await fetch("/api/enrich-candidates",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({candidates:missing.map(function(c){return{id:c.id,firstName:(c.full_name||"").split(" ")[0]||"",lastName:(c.full_name||"").split(" ").slice(1).join(" ")||"",company:c.current_company||"",email:null}})})});
if(res.ok){var data=await res.json();var enrichMap={};(data.candidates||[]).forEach(function(ec){if(ec.email&&ec.id)enrichMap[String(ec.id)]=ec});
var updated=matched.map(function(c){var e=enrichMap[String(c.id)];if(e){return Object.assign({},c,{email:e.email,phone_number:c.phone_number||e.phone||"",_enrichedVia:"zoominfo"})}return c});
setMatches(function(p){var n=Object.assign({},p);n[jobId]=updated;return n});
setMatchCache(jobId,updated);
toast({title:"Enriched "+data.enrichedCount+" emails ("+data.fromCache+" cached, "+data.fromZi+" new)",status:"success"})}
else{toast({title:"Enrichment failed",detail:"Server returned "+res.status,status:"error"})}}
catch(e){toast({title:"Enrichment failed",detail:e.message,status:"error"})}
setEnriching(null)};
var filteredJobs=jobs.filter(function(j){return(!jobSearch||j.position_name.toLowerCase().indexOf(jobSearch.toLowerCase())!==-1)&&(clientFilter==="all"||j.organization===clientFilter)}).sort(function(a,b){if(jobSort==="newest")return new Date(b.created_at)-new Date(a.created_at);if(jobSort==="oldest")return new Date(a.created_at)-new Date(b.created_at);return a.position_name.localeCompare(b.position_name)});
