<div><label style={{display:"block",color:"#a8a29e",fontSize:11,fontWeight:700,marginBottom:6}}>SEND TO</label><div style={{display:"flex",gap:6,marginBottom:8}}>{["client","internal"].map(function(t){return <button key={t} onClick={function(){setSubRecType(t)}} style={{flex:1,padding:"10px 14px",borderRadius:10,fontSize:12,fontWeight:700,background:subRecType===t?t==="client"?"#f59e0b":"#38bdf8":"rgba(0,0,0,0.3)",border:subRecType===t?"none":"1px solid rgba(255,255,255,0.08)",color:subRecType===t?"#111318":"#a8a29e",cursor:"pointer",textTransform:"capitalize"}}>{t}</button>})}</div>
<input value={subRecipient} onChange={function(e){setSubRecipient(e.target.value)}} placeholder={subRecType==="client"?"client@company.com":"team@yourcompany.com"} style={{width:"100%",padding:"10px 14px",background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.08)",borderRadius:10,color:"#f1f5f9",fontSize:13,outline:"none",boxSizing:"border-box"}}/></div>
