<div style={{flex:1}}><label style={{display:"block",color:"#a8a29e",fontSize:10,fontWeight:700,marginBottom:6}}>BODY</label><textarea value={body} onChange={function(e){setBody(e.target.value)}} placeholder="Generate with AI or type manually..." style={{width:"100%",minHeight:180,padding:"10px 12px",background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.08)",borderRadius:10,color:"#d6d3d1",fontSize:13,lineHeight:1.6,outline:"none",resize:"vertical",boxSizing:"border-box"}}/></div>
